  ('heelevel3-29a002de-moex-00131', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲至 A 賣場購物，發現原先價格 3,000 元的高級牛肉一包，竟被賣場誤
貼標示為 500 元的價格標籤，於是拿這包牛肉到櫃台結帳，結帳人員不
疑有他，讓甲成功結帳離開。A賣場事後清點帳目，發現貼錯標籤，故和
甲索討2,500元的貨款。甲十分不滿，在其設為公開的臉書留言，謊稱A
賣場常將低階牛肉標上高階牛肉的價格販售。請問甲的刑事責任如何？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "aceddd288727", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1111", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00132', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲開車載 A出遊，至杳無人跡之處看風景，甲突然提議要與 A性交，A
起先拒絕，但甲不斷強力要求，雖然並未動手或出言恫嚇，態度卻越來
越兇惡。A心想自己與甲體力差距懸殊，當地又無人相助，激怒甲只是
徒增傷害，於是屈從於甲的意思與其性交。在驅車回返途中，甲又和 A
說，剛剛性交的過程中感到 A病氣甚重，應是被靈體纏身，需再次性交
始能將陽氣傳入驅趕靈體。A確實罹患癌症，故信以為真，內心恐懼，
再次答應與甲性交。請問甲的刑事責任如何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "aceddd288727", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1111", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00133', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲以乙為被告向臺灣臺北地方法院（下稱臺北地院）起訴主張：甲住基
隆市、乙住臺北市文山區，乙為工作之故，向甲承租其所有坐落桃園市
之 A屋，因租期屆滿，乙拒絕返還，爰依租賃物返還請求權請求乙返還
A屋占有予原告。問：
法院應否闡明甲亦得對乙主張所有物返還請求權？如甲在法院審理
中追加所有物返還請求權，法院准許之，乙因而抗辯臺北地院對事件
全部無管轄權，其抗辯是否有理？（15 分）
如於一審法院審理中，法官行爭點整理程序，兩造於爭點簡化協議中，
同意在本件僅對於所有物返還請求權加以審理即可。如一審法院判決
甲敗訴，甲上訴後追加租賃物返還請求權，乙則抗辯甲之追加因違反
爭點簡化協議，應屬不合法，是否有理？（15 分）
本件訴訟，對於乙是否為無權占有一節有爭執，對此事實應由何人負
舉證責任？如甲為蒐集證據，持續一年左右，在乙之住處裝設針孔攝
影機，而取得乙向其配偶坦承其為無權占用之事實，如原告提出此一
攝影紀錄為證，法院得否利用？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "33d9ebb53cdd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1110", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00134', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲因竊盜罪嫌遭警詢問時，冒用乙名應詢，警察局未察而以乙犯竊盜罪
嫌函送檢察署偵辦。檢察官以乙竊盜罪嫌事證明確，未經訊問，即對乙
偵查終結，向地方法院簡易庭聲請簡易判決處刑，簡易庭法官亦以事證
明確，判決乙竊盜罪刑，處拘役50 日。乙收到判決書後，認為其未曾犯
罪而提起上訴，地方法院合議庭（A、B、C法官）開庭查明，撤銷原判
決，改判甲竊盜罪刑，仍處拘役 50 日。試問：（每小題 25分，共50 分）
甲對確定判決聲請再審，甲從傳票得知再審案件仍分由 A法官承辦，
認為 A 法官參與前審之判決，依法應自行迴避為由，聲請 A 法官迴
避。甲之聲請有無理由？
如 A法官以聲請無再審理由而裁定駁回甲之再審聲請，被告甲之辯護
人丙律師可否對該裁定提起抗告？如可，應以何人之名義為之？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "33d9ebb53cdd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1110", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00135', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'essay', '甲為原住民，登記為 A原住民保留地所有人，乙並非原住民，為經營民
宿，出資向甲購買 A地，之後並興建 B屋，為了擔保該出資並取得 B屋
的占有權源，乙從甲處取得 A地的抵押權、地上權後，再與原住民丙成
立借名登記契約，然後以丙的名義與甲簽訂 A地買賣契約，甲即將 A地
所有權移轉登記予丙。請問乙與丙間的借名登記契約、丙與甲間的買賣
契約、甲與乙間設定地上權行為及甲與丙間的所有權移轉登記行為效力
如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00136', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'essay', '甲於民國 105 年 5 月 10 日與乙公司簽訂房屋土地買賣契約（下稱系爭
買賣契約），向乙公司購買坐落高雄市的土地及坐落其上 4 樓透天厝（下
合稱系爭房地）。甲已給付 4 成自備款，雙方約定其餘 6 成房價由乙公
司協助甲洽定提供金融機構的貸款給付，並於簽約時，將系爭買賣契約
第 18 條關於「貸款差額超過原預定貸款金額 30%，雙方均得解除契約」
（此為主管機關公告的定型化契約應記載事項及不得記載事項）的約定，
予以刪除，並各自用印、簽名。然乙公司所接洽的銀行均拒絕甲貸予該
6 成房價，甲依系爭買賣契約第 18條於 108 年 10月 20 日函知乙公司解
除系爭契約，乙公司依系爭買賣契約第25條第3項沒入買賣總價之15%
違約金。請問甲與乙公司合意刪除「貸款差額超過原預定貸款金額 30%
時，雙方均得解除契約」的約定，是否有效？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00137', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於危險負擔之敘述，何者正確？', '["因不可歸責於雙方當事人之事由，致一方之給付僅一部不能者，他方免為對待給付之義務", "因不可歸責於雙方當事人之事由，致一方之給付全部不能者，他方免為對待給付之義務；如已 為全部或一部之對待給付者，得依關於無因管理之規定，請求返還", "甲出賣自己之A車於乙，雙方締結買賣契約，約好3日後一手交車一手交錢；孰料，締約隔天 A車被因地震倒塌的圍牆壓毀，由於不可歸責於甲，故甲仍得向乙請求價金", "甲出賣自己之A車於乙，雙方締結買賣契約，約好3日後一手交車一手交錢；孰料，締約隔天 乙試車時不慎撞毀A車，由於可歸責於乙，故甲仍得向乙請求價金 32620、33320"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00138', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲所有之A車，出於心中保留，贈與並移轉該車所有權於乙，嗣後乙出賣並移轉該車於第三人丙。 下列敘述，何者錯誤？', '["倘若乙不知甲心中保留，丙為善意且無重大過失之第三人時，丙取得A車之所有權", "倘若乙不知甲心中保留，丙為惡意第三人時，丙取得A車之所有權", "倘若乙明知甲心中保留，丙為善意且無重大過失之第三人時，丙取得A車之所有權", "倘若乙明知甲心中保留，丙為惡意第三人時，丙取得A車之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00139', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲向乙購買冰箱，約定分5期清償價金，於價金如期清償完畢時，甲始取得冰箱所有權。在清償 完畢前，該冰箱已由甲占有使用。倘若有第三人丙於條件成就前不慎毀損該冰箱，下列敘述，何 者錯誤？', '["乙得基於所有權人地位向丙主張侵權行為之損害賠償", "甲於條件成就時，得向丙主張損害賠償", "倘若甲對丙毀損冰箱無過失時，則甲仍須支付剩餘價金於乙", "縱使甲將冰箱出賣並移轉所有權於惡意之丁，丁仍取得該冰箱之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00140', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲逾越地界，擅自在乙所有之A地上種植蘋果樹，三年後蘋果樹結實纍纍。下列敘述，何者錯誤？', '["蘋果樹之所有權歸乙所有", "蘋果之收取權人為甲", "與蘋果樹分離之蘋果為獨立之物", "蘋果樹為A地之成分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
